INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (27, "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 155, 0, 8, "人助けが大好き！　前向き格闘娘", "A", "トゥインクルウィッシュ", 2, 44, "獣人族", "東山奈央", "ヒヨリ", 100101, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 158, 0, 4, "戦闘のサポートが得意な、心優しい少女", "O", "トゥインクルウィッシュ", 2, 47, "ヒューマン", "種田梨沙", "ユイ", 100201, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 163, 0, 1, "クールで何事にも真っ直ぐな剣士", "B", "トゥインクルウィッシュ", 2, 46, "魔族", "早見沙織", "レイ", 100301, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "いたずら、探検", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 128, 0, 8, "探検好きのイタズラっ子", "O", "リトルリリカル", 5, 27, "ヒューマン", "諸星すみれ", "ミソギ", 100401, 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (25, "ヒーローごっこ", "？？？", 146, 0, 11, "ヒーローに憧れる騎士見習いの少女", "O", "王宮騎士団（NIGHTMARE）", 8, 40, "獣人族", "下田麻美", "マツリ", 100501, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, "サックス", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 150, 0, 11, "甘え上手なみんなの人気者", "O", "悪魔偽王国軍（ディアボロス）", 7, 42, "魔族", "浅倉杏美", "アカリ", 100601, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (23, "プリンを食べること", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 130, 0, 1, "プリン大好きゴースト娘", "B", "悪魔偽王国軍（ディアボロス）", 7, 32, "魔族", "雨宮天", "ミヤコ", 100701, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "鏡で自分を見ること", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 150, 0, 10, "ボクは誰よりも美しい", "AB", "ヴァイスフリューゲル　ランドソル支部", 15, 40, "エルフ", "大空直美", "ユキ", 100801, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "小説執筆", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 159, 0, 7, "前世を信じる中二病患者、「疾風の冥姫」", "A", "トワイライトキャラバン", 13, 45, "魔族", "髙野麻美", "アンナ", 100901, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, "空想、ぬいぐるみ集め", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 155, 0, 9, "マホマホ王国のプリンセス", "O", "自警団（カォン）", 10, 42, "獣人族", "内田真礼", "マホ", 101001, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (25, "お裁縫", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 156, 0, 8, "人懐っこくてマシンガントークな妹系少女", "A", "ラビリンス", 3, 44, "ヒューマン", "阿澄佳奈", "リノ", 101101, 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (24, "妹と遊ぶこと、二度寝、昼寝、早寝", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 156, 0, 12, "みんなのために超能力を使う眠り姫", "A", "フォレスティエ", 6, 46, "エルフ", "大橋彩香", "ハツネ", 101201, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (21, "読書、魔法", "", 166, 0, 8, "オタク全開な魔法少女", "O", "トワイライトキャラバン", 13, 55, "魔族", "佳村はるか", "ナナカ", 101301, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "読書、推理", "test", 152, 0, 11, "頭脳明晰な美少女名探偵", "AB", "自警団（カォン）", 10, 41, "獣人族", "水瀬いのり", "カスミ", 101401, 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "絵本作り", "test", 165, 0, 9, "母性溢れる優しいみんなの「ミサト先生」", "O", "フォレスティエ", 6, 54, "エルフ", "國府田マリ子", "ミサト", 101501, 21);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "ファッション", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 167, 0, 4, "天真爛漫で人気者のカリスマモデル", "O", "ルーセント学院", 14, 48, "魔族", "上坂すみれ", "スズナ", 101601, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "踊り、空手", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 158, 0, 7, "いつでも「なんくるないさ～」な天然娘", "A", "自警団（カォン）", 10, 53, "獣人族", "高森奈津美", "カオリ", 101701, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 162, 0, 8, "多くの男性を魅了する無垢な女教師", "B", "ルーセント学院", 14, 52, "魔族", "伊藤静", "イオ", 101801, 23);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "かわいいもの集め", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 117, 0, 4, "お歌もにんじんも、ウサギさんも大好き♪", "O", "リトルリリカル", 5, 21, "獣人族", "日高里菜", "ミミ", 102001, 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "観劇、おままごと", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 150, 0, 6, "泣き虫で臆病な守ってあげたい女の子", "B", "サレンディア救護院", 9, 40, "ヒューマン", "植田佳奈", "クルミ", 102101, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, "ゲーム全般", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 150, 0, 11, "人見知りであまのじゃくな女の子", "O", "悪魔偽王国軍（ディアボロス）", 7, 40, "魔族", "原紗友里", "ヨリ", 102201, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "屋内でできる遊び", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 148, 0, 5, "ぷうきちといつも一緒！", "B", "サレンディア救護院", 9, 38, "ヒューマン", "芹澤優", "アヤネ", 102301, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "ご奉仕", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 154, 0, 12, "お嬢さまのためにがんばるドジっ娘メイド", "O", "サレンディア救護院", 9, 43, "ヒューマン", "悠木碧", "スズメ", 102501, 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "あんパン", "test", 144, 0, 1, "遊びと睡眠が何より大事なぐうたら娘", "B", "牧場（エリザベスパーク）", 11, 42, "獣人族", "小岩井ことり", "リン", 102601, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (30, "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 154, 0, 7, "運命の相手に一途すぎる乙女", "B", "トワイライトキャラバン", 13, 43, "魔族", "橋本ちなみ", "エリコ", 102701, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "経営、お茶会", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 156, 0, 10, "救護院を経営する優しい庶民派お嬢様", "A", "サレンディア救護院", 9, 43, "エルフ", "堀江由衣", "サレン", 102801, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (24, "舞台鑑賞、ダンス", "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 157, 0, 1, "歌って踊れる大人気アイドル", "B", "カルミナ", 4, 40, "ヒューマン", "日笠陽子", "ノゾミ", 102901, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (31, "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 163, 0, 8, "トーゴクの神秘、オシエテクダサイ！", "O", "ヴァイスフリューゲル　ランドソル支部", 15, 51, "ヒューマン", "佐藤聡美", "ニノン", 103001, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 157, 0, 12, "占いが得意な霊能少女", "AB", "悪魔偽王国軍（ディアボロス）", 7, 42, "魔族", "大坪由佳", "シノブ", 103101, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "慈善事業", "この私とともにいる限り、\nお金に不自由はさせませんわ！", 157, 0, 3, "一人前の商人を目指すパワフルお嬢様", "AB", "メルクリウス財団", 12, 45, "ヒューマン", "松嵜麗", "アキノ", 103201, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "漫才", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 142, 0, 3, "みんなを笑顔にするお笑い牧場主", "B", "牧場（エリザベスパーク）", 11, 35, "ヒューマン", "新田恵海", "マヒル", 103301, 20);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, "ウインドーショッピング", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 164, 0, 3, "純情でほっとけない大人の女性", "A", "メルクリウス財団", 12, 55, "エルフ", "今井麻美", "ユカリ", 103401, 22);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "お勉強", "test", 118, 0, 2, "礼儀正しくしっかり者のちびっ子優等生", "A", "リトルリリカル", 5, 21, "エルフ", "小倉唯", "キョウカ", 103601, 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "剣術、年長者をからかう", "test", 149, 0, 8, "義理堅くてからかい好きな剣術少女", "A", "王宮騎士団（NIGHTMARE）", 8, 43, "ヒューマン", "茅原実里", "トモ", 103701, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "読書、お散歩", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 153, 0, 11, "読書が趣味の病弱少女", "A", "牧場（エリザベスパーク）", 11, 40, "獣人族", "小清水亜美", "シオリ", 103801, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "友達作りのイメトレ", "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 158, 0, 6, "「友達」に憧れる、エルフの森の女の子", "AB", "フォレスティエ", 6, 44, "エルフ", "花澤香菜", "アオイ", 104001, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 163, 0, 6, "人々を守るために歌う、唱喚士の少女", "O", "カルミナ", 4, 46, "ヒューマン", "福原綾香", "チカ", 104201, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "お菓子作り", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 168, 0, 8, "男勝りで情に厚いワイルド娘", "O", "自警団（カォン）", 10, 54, "獣人族", "小松未可子", "マコト", 104301, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "世界征服", "test", 172, 0, 5, "かつては夜を支配した最強の吸血鬼", "A", "悪魔偽王国軍（ディアボロス）", 7, 50, "魔族", "丹下桜", "イリヤ", 104401, "??");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (19, "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 157, 0, 11, "妄想大好き！　ほんとは照れ屋な女の子", "AB", "ヴァイスフリューゲル　ランドソル支部", 15, 49, "ヒューマン", "長妻樹里", "クウカ", 104501, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 158, 0, 3, "弱きを助け強きをくじく猫娘", "AB", "メルクリウス財団", 12, 48, "獣人族", "沼倉愛美", "タマキ", 104601, 19);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (25, "格闘技、湯浴み", "？？？", 171, 0, 10, "素顔を見せない冷静沈着な女性騎士", "A", "王宮騎士団（NIGHTMARE）", 8, 50, "ヒューマン", "川澄綾子", "ジュン", 104701, 25);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "傭兵などのアルバイト", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 163, 0, 11, "仕事も私事も効率優先な傭兵少女", "O", "メルクリウス財団", 12, 49, "ヒューマン", "田所あずさ", "ミフユ", 104801, 20);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (24, "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 168, 0, 10, "お姉ちゃんがお世話してあげるからねっ！", "O", "ラビリンス", 3, 54, "ヒューマン", "生天目仁美", "シズル", 104901, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "ファッション誌鑑賞、コスメ集め", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 120, 0, 1, "ちょっとおませな恋に恋する女の子", "A", "ルーセント学院", 14, 22, "魔族", "久野美咲", "ミサキ", 105001, 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "研究、実験", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 166, 0, 3, "実験が趣味の危険な科学者", "A", "トワイライトキャラバン", 13, 53, "ヒューマン", "三石琴乃", "ミツキ", 105101, 27);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, "毛繕い、お喋り", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 150, 0, 3, "乙女チックなもふもふアニマル", "A", "牧場（エリザベスパーク）", 11, 100, "獣人族", "徳井青空", "リマ", 105201, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (28, "お菓子屋通い", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 140, 0, 7, "見た目も中身もお子ちゃまな異国の軍人", "A", "ヴァイスフリューゲル　ランドソル支部", 15, 33, "ヒューマン", "辻あゆみ", "モニカ", 105301, 17);
