INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "観察", "test", 155, 0, 4, "どこまでも一途に慕う、純情乙女", "O", "ヴァイスフリューゲル　ランドソル支部", 15, 43, "エルフ", "大関英里", "アユミ", 105501, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "釣り", "test", 167, 0, 7, "人情味溢れる粋でいなせな「姉御」", "B", "トワイライトキャラバン", 13, 54, "ヒューマン", "佐藤利奈", "ルカ", 105601, 25);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "冒険、おしゃべり", "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", 156, 0, 3, "空への冒険を夢見る騎空士の少女", "O", "？？？", "", 45, "ヒューマン", "金元寿子", "ジータ", 105701, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (31, "食べ歩き、料理", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 156, 0, 3, "いつも元気な腹ペコ少女", "O", "美食殿", 1, 46, "ヒューマン", "M・A・O", "ペコリーヌ", 105801, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 140, 0, 5, "主を慕う、小さなガイド役", "B", "美食殿", 1, 35, "エルフ", "伊藤美来", "コッコロ", 105901, 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "猫と遊ぶ", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 152, 0, 9, "行き倒れの謎のネコミミ魔法使い", "A", "美食殿", 1, 39, "獣人族", "立花理香", "キャル", 106001, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "冒険、思い出話", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 148, 0, 8, "さまよえる謎の少女", "O", "？？？", "", 40, "ヒューマン", "潘めぐみ", "ムイミ", 106101, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "キレイな葉っぱを集めること", "", 155, 0, 6, "森番を目指すエルフの少女", "O", "？？？", "", 42, "エルフ", "優木かな", "アリサ", 106301, 15);
