INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, "絵画、読書", "", 168, 0, 4, "妖しい微笑で全てを見透かす臥竜の頭領", "O", "ドラゴンズネスト", 17, "???", "ドラゴン族", "大西沙織", "ホマレ", 106701, 25);
