INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (24, "物真似、芸術鑑賞", "", 149, 0, 3, "研究所に隠れ住む物静かなお姉さん", "O", "？？？", "", "??", "エルフ", "井口裕香", "ネネカ", 107001, 24);
