INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (31, "食べ歩き、料理", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 156, 0, 3, "いつも元気な腹ペコ少女", "O", "美食殿", 1, 46, "ヒューマン", "M・A・O", "ペコリーヌ（サマー）", 107501, 17);
