INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "ご奉仕", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 154, 0, 12, "お嬢さまのためにがんばるドジっ娘メイド", "O", "サレンディア救護院", 9, 43, "ヒューマン", "悠木碧", "スズメ（サマー）", 107701, 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "猫と遊ぶ", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 152, 0, 9, "行き倒れの謎のネコミミ魔法使い", "A", "美食殿", 1, 39, "獣人族", "立花理香", "キャル（サマー）", 107801, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 158, 0, 3, "弱きを助け強きをくじく猫娘", "AB", "メルクリウス財団", 12, 48, "獣人族", "沼倉愛美", "タマキ（サマー）", 107901, 19);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "傭兵などのアルバイト", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 163, 0, 11, "仕事も私事も効率優先な傭兵少女", "O", "メルクリウス財団", 12, 49, "ヒューマン", "田所あずさ", "ミフユ（サマー）", 108001, 20);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 157, 0, 12, "占いが得意な霊能少女", "AB", "悪魔偽王国軍（ディアボロス）", 7, 42, "魔族", "大坪由佳", "シノブ（ハロウィン）", 108101, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (23, "プリンを食べること", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 130, 0, 1, "プリン大好きゴースト娘", "B", "悪魔偽王国軍（ディアボロス）", 7, 32, "魔族", "雨宮天", "ミヤコ（ハロウィン）", 108201, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "ファッション誌鑑賞、コスメ集め", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 120, 0, 1, "ちょっとおませな恋に恋する女の子", "A", "ルーセント学院", 14, 22, "魔族", "久野美咲", "ミサキ（ハロウィン）", 108301, 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 163, 0, 6, "人々を守るために歌う、唱喚士の少女", "O", "カルミナ", 4, 46, "ヒューマン", "福原綾香", "チカ（クリスマス）", 108401, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "観劇、おままごと", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 150, 0, 6, "泣き虫で臆病な守ってあげたい女の子", "B", "サレンディア救護院", 9, 40, "ヒューマン", "植田佳奈", "クルミ（クリスマス）", 108501, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "屋内でできる遊び", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 148, 0, 5, "ぷうきちといつも一緒！", "B", "サレンディア救護院", 9, 38, "ヒューマン", "芹澤優", "アヤネ（クリスマス）", 108601, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (27, "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 155, 0, 8, "人助けが大好き！　前向き格闘娘", "A", "トゥインクルウィッシュ", 2, 44, "獣人族", "東山奈央", "ヒヨリ（ニューイヤー）", 108701, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 158, 0, 4, "戦闘のサポートが得意な、心優しい少女", "O", "トゥインクルウィッシュ", 2, 47, "ヒューマン", "種田梨沙", "ユイ（ニューイヤー）", 108801, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 163, 0, 1, "クールで何事にも真っ直ぐな剣士", "B", "トゥインクルウィッシュ", 2, 46, "魔族", "早見沙織", "レイ（ニューイヤー）", 108901, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (30, "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 154, 0, 7, "運命の相手に一途すぎる乙女", "B", "トワイライトキャラバン", 13, 43, "魔族", "橋本ちなみ", "エリコ（バレンタイン）", 109001, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (24, "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 168, 0, 10, "お姉ちゃんがお世話してあげるからねっ！", "O", "ラビリンス", 3, 54, "ヒューマン", "生天目仁美", "シズル（バレンタイン）", 109101, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "読書", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 156, 0, 12, "英霊と契約を結んだマナリアの天才王女", "AB", "？？？", "", 55, "ヒューマン", "日笠陽子", "アン", 109201, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "食べること、眠ること", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 144, 0, 2, "マナリア魔法学院の新入生", "O", "？？？", "", 45, "ヒューマン", "こやまきみこ", "ルゥ", 109301, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "ピアノ", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 167, 0, 11, "人を超越した力を有す心優しい竜姫", "B", "？？？", "", 67, "半人半竜", "福原綾香", "グレア", 109401, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (19, "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 157, 0, 11, "妄想大好き！　ほんとは照れ屋な女の子", "AB", "ヴァイスフリューゲル　ランドソル支部", 15, 49, "ヒューマン", "長妻樹里", "クウカ（オーエド）", 109501, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (31, "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 163, 0, 8, "トーゴクの神秘、オシエテクダサイ！", "O", "ヴァイスフリューゲル　ランドソル支部", 15, 51, "ヒューマン", "佐藤聡美", "ニノン（オーエド）", 109601, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "演劇鑑賞、詩文", "", 154, 0, 2, "鬼がかりの万能妹メイド", "?", "？？？", "", "??", "鬼族", "水瀬いのり", "レム", 109701, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "読書", "", 154, 0, 2, "毒舌系鬼姉メイド", "?", "？？？", "", "??", "鬼族", "村川梨衣", "ラム", 109801, 17);
