INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "ファッション", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 167, 0, 4, "天真爛漫で人気者のカリスマモデル", "O", "ルーセント学院", 14, 48, "魔族", "上坂すみれ", "スズナ（サマー）", 110001, 17);
