INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (31, "食べ歩き、料理", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 156, 0, 3, "いつも元気な腹ペコ少女", "O", "美食殿", 1, 46, "ヒューマン", "M・A・O", "ぺコリーヌ（ニューイヤー）", 111801, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 140, 0, 5, "主を慕う、小さなガイド役", "B", "美食殿", 1, 35, "エルフ", "伊藤美来", "コッコロ（ニューイヤー）", 111901, 11);
