INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "ご奉仕", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 154, 0, 12, "お嬢さまのためにがんばるドジっ娘メイド", "O", "サレンディア救護院", 9, 43, "ヒューマン", "悠木碧", "スズメ（ニューイヤー）", 112101, 15);
