INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "読書、お散歩", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 153, 0, 11, "読書が趣味の病弱少女", "A", "牧場（エリザベスパーク）", 11, 40, "獣人族", "小清水亜美", "シオリ（マジカル）", 112301, 14);
