INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "漫才", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 142, 0, 3, "みんなを笑顔にするお笑い牧場主", "B", "牧場（エリザベスパーク）", 11, 35, "ヒューマン", "新田恵海", "マヒル（レンジャー）", 112801, 20);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (25, "お裁縫", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 156, 0, 8, "人懐っこくてマシンガントークな妹系少女", "A", "ラビリンス", 3, 44, "ヒューマン", "阿澄佳奈", "リノ（ワンダー）", 112901, 15);
