INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "小説執筆", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 159, 0, 7, "前世を信じる中二病患者、「疾風の冥姫」", "A", "トワイライトキャラバン", 13, 45, "魔族", "髙野麻美", "アンナ（サマー）", 113201, 17);
