INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (25, "格闘技、湯浴み", "", 171, 0, 10, "素顔を見せない冷静沈着な女性騎士", "A", "王宮騎士団（NIGHTMARE）", 8, 50, "ヒューマン", "川澄綾子", "ジュン（サマー）", 113601, 25);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, "サックス", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 150, 0, 11, "甘え上手なみんなの人気者", "O", "悪魔偽王国軍（ディアボロス）", 7, 42, "魔族", "浅倉杏美", "アカリ（エンジェル）", 113701, 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, "ゲーム全般", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 150, 0, 11, "人見知りであまのじゃくな女の子", "O", "悪魔偽王国軍（ディアボロス）", 7, 40, "魔族", "原紗友里", "ヨリ（エンジェル）", 113801, 13);
