INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 163, 0, 1, "クールで何事にも真っ直ぐな剣士", "B", "トゥインクルウィッシュ", 2, 46, "魔族", "早見沙織", "レイ（ハロウィン）", 114001, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (25, "ヒーローごっこ", "", 146, 0, 11, "ヒーローに憧れる騎士見習いの少女", "O", "王宮騎士団（NIGHTMARE）", 8, 40, "獣人族", "下田麻美", "マツリ（ハロウィン）", 114101, 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (28, "お菓子屋通い", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 140, 0, 7, "見た目も中身もお子ちゃまな異国の軍人", "A", "ヴァイスフリューゲル　ランドソル支部", 15, 33, "ヒューマン", "辻あゆみ", "モニカ（マジカル）", 114201, 17);
