INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "慈善事業", "この私とともにいる限り、\nお金に不自由はさせませんわ！", 157, 0, 3, "一人前の商人を目指すパワフルお嬢様", "AB", "メルクリウス財団", 12, 45, "ヒューマン", "松嵜麗", "アキノ（クリスマス）", 114401, 18);
