INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, "ウインドーショッピング", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 164, 0, 3, "純情でほっとけない大人の女性", "A", "メルクリウス財団", 12, 55, "エルフ", "今井麻美", "ユカリ（クリスマス）", 114601, 22);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "冒険、思い出話", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 148, 0, 8, "さまよえる謎の少女", "O", "？？？", "", 40, "ヒューマン", "潘めぐみ", "ムイミ（ニューイヤー）", 114701, 16);
