INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 140, 0, 5, "主を慕う、小さなガイド役", "B", "美食殿", 1, 35, "エルフ", "伊藤美来", "コッコロ（儀装束）", 115501, 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 158, 0, 4, "戦闘のサポートが得意な、心優しい少女", "O", "トゥインクルウィッシュ", 2, 47, "ヒューマン", "種田梨沙", "ユイ（儀装束）", 115601, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "読書、推理", "", 152, 0, 11, "頭脳明晰な美少女名探偵", "AB", "自警団（カォン）", 10, 41, "獣人族", "水瀬いのり", "カスミ（サマー）", 115701, 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, "毛繕い、お喋り", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 150, 0, 3, "乙女チックなもふもふアニマル", "A", "牧場（エリザベスパーク）", 11, 100, "獣人族", "徳井青空", "リマ（シンデレラ）", 115801, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "お菓子作り", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 168, 0, 8, "男勝りで情に厚いワイルド娘", "O", "自警団（カォン）", 10, 54, "獣人族", "小松未可子", "マコト（シンデレラ）", 115901, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, "空想、ぬいぐるみ集め", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 155, 0, 9, "マホマホ王国のプリンセス", "O", "自警団（カォン）", 10, 42, "獣人族", "内田真礼", "マホ（シンデレラ）", 116001, 16);
