INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 158, 0, 3, "弱きを助け強きをくじく猫娘", "AB", "メルクリウス財団", 12, 48, "獣人族", "沼倉愛美", "タマキ（作業服）", 116801, 19);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "傭兵などのアルバイト", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 163, 0, 11, "仕事も私事も効率優先な傭兵少女", "O", "メルクリウス財団", 12, 49, "ヒューマン", "田所あずさ", "ミフユ（作業服）", 116901, 20);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (30, "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 154, 0, 7, "運命の相手に一途すぎる乙女", "B", "トワイライトキャラバン", 13, 43, "魔族", "橋本ちなみ", "エリコ（サマー）", 117001, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (24, "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 168, 0, 10, "お姉ちゃんがお世話してあげるからねっ！", "O", "ラビリンス", 3, 54, "ヒューマン", "生天目仁美", "シズル（サマー）", 117101, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (24, "舞台鑑賞、ダンス", "", 157, 0, 1, "歌って踊れる大人気アイドル", "B", "カルミナ", 4, 40, "ヒューマン", "日笠陽子", "ノゾミ（サマー）", 117201, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 163, 0, 6, "人々を守るために歌う、唱喚士の少女", "O", "カルミナ", 4, 46, "ヒューマン", "福原綾香", "チカ（サマー）", 117301, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "裁縫", "", 153, 0, 9, "ファッション大好きなキュートガール", "AB", "カルミナ", 4, 45, "ヒューマン", "木戸衣吹", "ツムギ（サマー）", 117401, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "研究、実験", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 166, 0, 3, "実験が趣味の危険な科学者", "A", "トワイライトキャラバン", 13, 53, "ヒューマン", "三石琴乃", "ミツキ（オーエド）", 117501, 27);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "鏡で自分を見ること", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 150, 0, 10, "ボクは誰よりも美しい", "AB", "ヴァイスフリューゲル　ランドソル支部", 15, 40, "エルフ", "大空直美", "ユキ（オーエド）", 117601, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "踊り、空手", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 158, 0, 7, "いつでも「なんくるないさ～」な天然娘", "A", "自警団（カォン）", 10, 53, "獣人族", "高森奈津美", "カオリ（ハロウィン）", 117701, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (31, "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 163, 0, 8, "トーゴクの神秘、オシエテクダサイ！", "O", "ヴァイスフリューゲル　ランドソル支部", 15, 51, "ヒューマン", "佐藤聡美", "ニノン（ハロウィン）", 117801, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "ファッション", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 167, 0, 4, "天真爛漫で人気者のカリスマモデル", "O", "ルーセント学院", 14, 48, "魔族", "上坂すみれ", "スズナ（ハロウィン）", 117901, 17);
