INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "小説執筆", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 159, 0, 7, "前世を信じる中二病患者、「疾風の冥姫」", "A", "トワイライトキャラバン", 13, 45, "魔族", "髙野麻美", "アンナ（パイレーツ）", 121901, 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 157, 0, 12, "占いが得意な霊能少女", "AB", "悪魔偽王国軍（ディアボロス）", 7, 42, "魔族", "大坪由佳", "シノブ（パイレーツ）", 122001, 18);
