INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "お散歩、お料理", "", 149, 0, 12, "けんぞくのご主人様", "AB", "？？？", "", 41, "魔族", "釘宮理恵", "ヴァンピィ", 122301, "??");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (27, "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 155, 0, 8, "人助けが大好き！　前向き格闘娘", "A", "トゥインクルウィッシュ", 2, 44, "獣人族", "東山奈央", "ヒヨリ（サマー）", 122401, 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 163, 0, 1, "クールで何事にも真っ直ぐな剣士", "B", "トゥインクルウィッシュ", 2, 46, "魔族", "早見沙織", "レイ（サマー）", 122501, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 158, 0, 4, "戦闘のサポートが得意な、心優しい少女", "O", "トゥインクルウィッシュ", 2, 47, "ヒューマン", "種田梨沙", "ユイ（サマー）", 122601, 17);
