INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "いたずら、探検", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 128, 0, 8, "探検好きのイタズラっ子", "O", "リトルリリカル", 5, 27, "ヒューマン", "諸星すみれ", "ミソギ（サマー）", 122801, 9);
