INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "屋内でできる遊び", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 148, 0, 5, "ぷうきちといつも一緒！", "B", "サレンディア救護院", 9, 38, "ヒューマン", "芹澤優", "アヤネ（エクスプローラー）", 123201, 14);
