INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (19, "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 157, 0, 11, "妄想大好き！　ほんとは照れ屋な女の子", "AB", "ヴァイスフリューゲル　ランドソル支部", 15, 49, "ヒューマン", "長妻樹里", "クウカ（サマー）", 127001, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 157, 0, 12, "占いが得意な霊能少女", "AB", "悪魔偽王国軍（ディアボロス）", 7, 42, "魔族", "大坪由佳", "シノブ（サマー）", 127101, 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "猫と遊ぶ", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 152, 0, 9, "行き倒れの謎のネコミミ魔法使い", "A", "美食殿", 1, 39, "獣人族", "立花理香", "キャル（編入生）", 127201, 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "ファッション", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 167, 0, 4, "天真爛漫で人気者のカリスマモデル", "O", "ルーセント学院", 14, 48, "魔族", "上坂すみれ", "スズナ（編入生）", 127301, 17);
