INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (27, "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 155, 0, 8, "人助けが大好き！　前向き格闘娘", "A", "トゥインクルウィッシュ", 2, 44, "獣人族", "東山奈央", "ヒヨリ", 900103, 16);
